import { useState, useEffect } from "react";
import axios from "axios";

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement
} from "chart.js";
import { Line } from "react-chartjs-2";

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement);

const API = "http://localhost:5000";

export default function App() {
  const [posts, setPosts] = useState([]);
  const [analytics, setAnalytics] = useState([]);
  const [selected, setSelected] = useState(null);

  const generate = async () => {
    const res = await axios.get(`${API}/generate-multiple`);
    setPosts(res.data.posts);
  };

  const approve = async () => {
    await axios.post(`${API}/approve`, {
      content: posts[selected].content
    });
  };

  const post = async () => {
    await axios.post(`${API}/post`);
    fetchAnalytics();
  };

  const fetchAnalytics = async () => {
    const res = await axios.get(`${API}/analytics`);
    setAnalytics(res.data);
  };

  const improve = async (i) => {
    const res = await axios.post(`${API}/improve`, {
      content: posts[i].content
    });

    const updated = [...posts];
    updated[i].content = res.data.improved;
    setPosts(updated);
  };

  useEffect(() => {
    fetchAnalytics();
  }, []);

  const chartData = {
    labels: analytics.map((_, i) => `Post ${i + 1}`),
    datasets: [{
      label: "Engagement %",
      data: analytics.map(a => (a.engagement || 0) * 100)
    }]
  };

  return (
    <div style={{ padding: 20 }}>
      <h1>LinkedIn AI Dashboard</h1>

      <button onClick={generate}>Generate</button>

      {posts.map((p, i) => (
        <div key={i}>
          <textarea value={p.content} readOnly />
          <button onClick={() => setSelected(i)}>Select</button>
          <button onClick={() => improve(i)}>Improve</button>
        </div>
      ))}

      <button onClick={approve}>Approve</button>
      <button onClick={post}>Post</button>

      <Line data={chartData} />

      {analytics.map(a => (
        <div key={a.id}>
          <p>{a.content}</p>
          <p>{(a.engagement * 100).toFixed(2)}%</p>
        </div>
      ))}
    </div>
  );
}
